VALUES
  ('optician-moex-00509', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '水凝膠材料其特性表現下列敘述何者錯誤？', '["在水合狀態下，水凝膠大多柔軟且有彈性，其彈性模量較硬式隱形眼鏡高", "軟式鏡片在水合狀態下，模量約 0.2~1.5MPa 的範圍內", "軟式隱形眼鏡經過烤箱輔助脫水後，其特性會變得較未脫水前硬且脆", "大部分的水凝膠材質製作之軟式隱形眼鏡具有黏彈性，當施加應力時，會隨著時間而變形，在應力消除 後，可逐漸恢復"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00510', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡材料之透氧性（DK）與傳氧性（DK/t）在同材質與度數的隱形眼鏡中心厚度變薄後，下列何者正確？', '["透氧性（DK）值不變，傳氧性（DK/t）值變低", "傳氧性（DK/t）值不變，透氧性（DK）值變高", "透氧性（DK）值不變，傳氧性（DK/t）值變高", "傳氧性（DK/t）值不變，透氧性（DK）值變低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00511', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '由OttoWichterle於1951年發明，第一種用於製造軟性隱形眼鏡的方法為何？', '["旋轉成形", "鑄造成形", "車削法", "混和成形"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00512', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一軟式隱形眼鏡材質表現出較低的蛋白質沉積但不可使用加熱消毒，此隱形眼鏡在 FDA 分類最可能是 屬於第幾類材質？', '["第一類", "第二類", "第三類", "第四類"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00513', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種交互作用或鍵結不是淚液能濕潤鏡片的原因？', '["氫鍵結（hydrogenbonding）", "疏水交互作用（hydrophobicinteraction）", "靜電交互作用（electrostaticinteraction）", "共價鍵結（covalentbonding）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00514', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種材質常運用在眼用的舒適滴劑（comfortdrops），目前也運用在拋棄式軟式隱形眼鏡來增加鏡片的 舒適度？', '["聚乙烯醇（polyvinylalcohol,PVA）", "甲基丙烯酸甲酯（methylmethacrylate,MMA）", "甲基丙烯酸（methacrylicacid,MAA）", "乙二醇二甲基丙烯酸酯（ethyleneglycoldimethacrylate,EGDMA）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00515', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡含水量的敘述，下列何者正確？', '["鏡片含水量越高，越適合眼睛乾澀者使用", "鏡片含水量越高，所需搭配之鏡片厚度要相對較厚，以保持一定耐用度", "水膠隱形眼鏡的含水量越低，透氧度較高", "鏡片含水量越低，越容易產生蛋白質沉積物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00516', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於硬式鏡片（RGP）的保養，下列何者正確？', '["當過氧化氫護理液被中和後，溶液中有硫柳汞鈉（thimerosalsodium）", "硬式鏡片多功能保養液（MPS）可以清潔、消毒、保濕、去除蛋白質且不含防腐劑", "當過氧化氫護理液被中和後，鏡片在溶液中浸泡超過5天，不用在戴鏡片前重複消毒和中和程序", "過氧化氫護理方式比多功能保養液更能溶解鏡片表面的蛋白質和脂質"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00517', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '戴軟式鏡片有8年經歷的配戴者，目前鏡片使用3個月，在一次複檢時，鏡片檢查發現一個小的圓形橙色 污點（rustspot）。下列那一項較不可能或處置不適當？', '["配戴者可能使用自來水浸泡或沖洗鏡片", "配戴者可能眼睛（eyeandlid）有金屬異物嵌入", "建議用雙氧水隱形眼鏡清潔液，不用更換鏡片", "建議更換成日拋隱形眼鏡片"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00518', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是硬式隱形眼鏡保養液現在或以前常用的防腐劑？', '["氯化苯甲烴胺（benzalkoniumchloride）", "氯己定（chlorhexidine）", "硫柳汞（thimerosal）", "聚乙烯醇（polyvinylalcohol）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
